package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

object Prefs {
    private const val PREF_NAME = "auth_prefs"
    private const val KEY_BIOMETRIC_AUTHENTICATED = "biometric_authenticated"
    private const val KEY_LOGGED_IN = "logged_in"

    private fun prefs(context: Context): SharedPreferences {
        return context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)
    }

    fun isBiometricAuthenticated(context: Context): Boolean {
        return prefs(context).getBoolean(KEY_BIOMETRIC_AUTHENTICATED, false)
    }

    fun setBiometricAuthenticated(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_BIOMETRIC_AUTHENTICATED, value).apply()
    }

    fun isLoggedIn(context: Context): Boolean {
        return prefs(context).getBoolean(KEY_LOGGED_IN, false)
    }

    fun setLoggedIn(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_LOGGED_IN, value).apply()
    }

    fun clearAuth(context: Context) {
        prefs(context).edit()
            .putBoolean(KEY_BIOMETRIC_AUTHENTICATED, false)
            .putBoolean(KEY_LOGGED_IN, false)
            .apply()
    }
}

class SplashActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (Prefs.isBiometricAuthenticated(this) || Prefs.isLoggedIn(this)) {
            startActivity(Intent(this, HomeActivity::class.java))
        } else {
            startActivity(Intent(this, LoginActivity::class.java))
        }
        finish()
    }
}

class LoginActivity : AppCompatActivity() {

    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private lateinit var etUsername: EditText
    private lateinit var etPassword: EditText
    private lateinit var btnPasswordLogin: Button
    private lateinit var btnBiometricLogin: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        if (Prefs.isBiometricAuthenticated(this) || Prefs.isLoggedIn(this)) {
            openHome()
            return
        }

        etUsername = findViewById(R.id.etUsername)
        etPassword = findViewById(R.id.etPassword)
        btnPasswordLogin = findViewById(R.id.btnPasswordLogin)
        btnBiometricLogin = findViewById(R.id.btnBiometricLogin)

        setupBiometric()
        setupActions()
        updateBiometricAvailability()
    }

    private fun setupActions() {
        btnPasswordLogin.setOnClickListener {
            val username = etUsername.text?.toString()?.trim().orEmpty()
            val password = etPassword.text?.toString().orEmpty()

            if (username.isEmpty() || password.isEmpty()) {
                Toast.makeText(this, "Enter username and password", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            if (username == "demo" && password == "password123") {
                Prefs.setLoggedIn(this, true)
                Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show()
                openHome()
            } else {
                Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show()
            }
        }

        btnBiometricLogin.setOnClickListener {
            showBiometricPrompt()
        }
    }

    private fun setupBiometric() {
        executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Prefs.setBiometricAuthenticated(this@LoginActivity, true)
                    Prefs.setLoggedIn(this@LoginActivity, true)
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint verified successfully",
                        Toast.LENGTH_SHORT
                    ).show()
                    openHome()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric unavailable. Use password to continue.",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint not recognized. You can use password login.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            }
        )

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Quick sign in")
            .setSubtitle("Use your fingerprint for fast access")
            .setDescription("Authenticate to skip login next time")
            .setNegativeButtonText("Use password")
            .build()
    }

    private fun updateBiometricAvailability() {
        when (BiometricManager.from(this).canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                btnBiometricLogin.isEnabled = true
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                btnBiometricLogin.isEnabled = false
                Toast.makeText(this, "Biometric hardware not available", Toast.LENGTH_SHORT).show()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                btnBiometricLogin.isEnabled = false
                Toast.makeText(this, "Biometric sensor is currently unavailable", Toast.LENGTH_SHORT).show()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                btnBiometricLogin.isEnabled = false
                Toast.makeText(this, "No fingerprint enrolled. Use password login.", Toast.LENGTH_SHORT).show()
            }
            else -> {
                btnBiometricLogin.isEnabled = false
                Toast.makeText(this, "Biometric login unavailable. Use password.", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun openHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    private lateinit var btnLogout: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (!Prefs.isBiometricAuthenticated(this) && !Prefs.isLoggedIn(this)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
            return
        }

        setContentView(R.layout.activity_home)
        btnLogout = findViewById(R.id.btnLogout)

        btnLogout.setOnClickListener {
            Prefs.clearAuth(this)
            Toast.makeText(this, "Logged out", Toast.LENGTH_SHORT).show()
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}